const HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no\">\n<title>KiddoLearn \u2014 Learn & Read</title>\n<link href=\"https://fonts.googleapis.com/css2?family=Fredoka+One&family=Nunito:wght@400;600;700;800;900&display=swap\" rel=\"stylesheet\">\n<style>\n*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\n:root {\n  --bg: #FFF8F0;\n  --bg2: #FFF3E8;\n  --card: #FFFFFF;\n  --border: #FFD6A5;\n  --orange: #FF7A2F;\n  --orange2: #FF9A5C;\n  --yellow: #FFD166;\n  --green: #06D6A0;\n  --blue: #118AB2;\n  --pink: #EF476F;\n  --purple: #9B5DE5;\n  --text: #2D2D2D;\n  --text2: #666;\n  --shadow: 0 4px 20px rgba(255,122,47,0.15);\n  --radius: 20px;\n  --font-d: 'Fredoka One', cursive;\n  --font-b: 'Nunito', sans-serif;\n}\n\n/* BEDTIME MODE */\nbody.bedtime {\n  --bg: #0D1B2A;\n  --bg2: #112233;\n  --card: #1A2E44;\n  --border: #2A4060;\n  --text: #E8F4FD;\n  --text2: #8BA7C0;\n  --orange: #7B9FBF;\n  --orange2: #5A8AB0;\n}\n\nbody {\n  background: var(--bg);\n  color: var(--text);\n  font-family: var(--font-b);\n  min-height: 100vh;\n  overflow-x: hidden;\n  transition: background 0.5s, color 0.5s;\n}\n\n/* \u2500\u2500 FLOATING BG SHAPES \u2500\u2500 */\n.bg-shapes {\n  position: fixed;\n  inset: 0;\n  pointer-events: none;\n  z-index: 0;\n  overflow: hidden;\n}\n.shape {\n  position: absolute;\n  border-radius: 50%;\n  opacity: 0.06;\n  animation: float 8s ease-in-out infinite;\n}\n.shape-1 { width: 300px; height: 300px; background: var(--orange); top: -100px; right: -50px; animation-delay: 0s; }\n.shape-2 { width: 200px; height: 200px; background: var(--blue); bottom: 100px; left: -80px; animation-delay: 2s; }\n.shape-3 { width: 150px; height: 150px; background: var(--purple); top: 40%; right: -40px; animation-delay: 4s; }\n@keyframes float {\n  0%,100% { transform: translateY(0) scale(1); }\n  50% { transform: translateY(-20px) scale(1.05); }\n}\n\n/* \u2500\u2500 SCREENS \u2500\u2500 */\n.screen { display: none; position: relative; z-index: 1; min-height: 100vh; }\n.screen.active { display: flex; flex-direction: column; }\n\n/* \u2500\u2500 HOME SCREEN \u2500\u2500 */\n#home {\n  padding: 24px 20px 40px;\n  align-items: center;\n}\n\n.home-header {\n  width: 100%;\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  margin-bottom: 32px;\n}\n\n.logo {\n  font-family: var(--font-d);\n  font-size: 28px;\n  color: var(--orange);\n  letter-spacing: 0.02em;\n}\n.logo span { color: var(--blue); }\n\n.header-btns { display: flex; gap: 10px; }\n\n.icon-btn {\n  width: 44px;\n  height: 44px;\n  border-radius: 12px;\n  border: 2px solid var(--border);\n  background: var(--card);\n  font-size: 20px;\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  transition: all 0.2s;\n  box-shadow: 0 2px 8px rgba(0,0,0,0.08);\n}\n.icon-btn:hover { transform: scale(1.05); }\n\n.hero-mascot {\n  font-size: 80px;\n  margin-bottom: 8px;\n  animation: bounce 2s ease-in-out infinite;\n}\n@keyframes bounce {\n  0%,100% { transform: translateY(0); }\n  50% { transform: translateY(-12px); }\n}\n\n.hero-title {\n  font-family: var(--font-d);\n  font-size: 36px;\n  color: var(--text);\n  text-align: center;\n  margin-bottom: 6px;\n}\n.hero-sub {\n  font-size: 16px;\n  color: var(--text2);\n  text-align: center;\n  margin-bottom: 36px;\n  font-weight: 600;\n}\n\n.section-title {\n  font-family: var(--font-d);\n  font-size: 22px;\n  color: var(--text);\n  width: 100%;\n  margin-bottom: 16px;\n}\n\n/* \u2500\u2500 MODE CARDS \u2500\u2500 */\n.mode-grid {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 14px;\n  width: 100%;\n  max-width: 500px;\n  margin-bottom: 32px;\n}\n\n.mode-card {\n  background: var(--card);\n  border: 2.5px solid var(--border);\n  border-radius: var(--radius);\n  padding: 20px 16px;\n  cursor: pointer;\n  transition: all 0.2s;\n  text-align: center;\n  box-shadow: var(--shadow);\n  position: relative;\n  overflow: hidden;\n}\n.mode-card::before {\n  content: '';\n  position: absolute;\n  top: 0; left: 0; right: 0;\n  height: 4px;\n  border-radius: 4px 4px 0 0;\n}\n.mode-card.orange::before { background: var(--orange); }\n.mode-card.blue::before { background: var(--blue); }\n.mode-card.green::before { background: var(--green); }\n.mode-card.purple::before { background: var(--purple); }\n\n.mode-card:hover { transform: translateY(-4px); box-shadow: 0 8px 30px rgba(255,122,47,0.2); }\n.mode-card:active { transform: translateY(0); }\n\n.mode-emoji { font-size: 36px; margin-bottom: 8px; display: block; }\n.mode-name { font-family: var(--font-d); font-size: 16px; color: var(--text); margin-bottom: 4px; }\n.mode-desc { font-size: 12px; color: var(--text2); font-weight: 600; }\n.mode-badge {\n  position: absolute;\n  top: 8px; right: 8px;\n  background: var(--orange);\n  color: white;\n  font-size: 9px;\n  font-weight: 800;\n  padding: 2px 7px;\n  border-radius: 100px;\n  font-family: var(--font-b);\n  letter-spacing: 0.05em;\n}\n\n/* \u2500\u2500 STREAK BAR \u2500\u2500 */\n.streak-bar {\n  width: 100%;\n  max-width: 500px;\n  background: var(--card);\n  border: 2px solid var(--border);\n  border-radius: 16px;\n  padding: 16px 20px;\n  display: flex;\n  align-items: center;\n  gap: 16px;\n  box-shadow: var(--shadow);\n}\n.streak-icon { font-size: 28px; }\n.streak-info { flex: 1; }\n.streak-label { font-size: 12px; font-weight: 700; color: var(--text2); text-transform: uppercase; letter-spacing: 0.08em; }\n.streak-val { font-family: var(--font-d); font-size: 22px; color: var(--orange); }\n.streak-dots { display: flex; gap: 6px; }\n.streak-dot { width: 10px; height: 10px; border-radius: 50%; background: var(--border); }\n.streak-dot.done { background: var(--orange); }\n\n/* \u2500\u2500 BACK BUTTON \u2500\u2500 */\n.back-btn {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  background: var(--card);\n  border: 2px solid var(--border);\n  border-radius: 12px;\n  padding: 10px 16px;\n  font-family: var(--font-b);\n  font-size: 14px;\n  font-weight: 700;\n  color: var(--text);\n  cursor: pointer;\n  transition: all 0.2s;\n}\n.back-btn:hover { transform: scale(1.02); }\n\n/* \u2500\u2500 FLASHCARD SCREEN \u2500\u2500 */\n#flashcards {\n  padding: 20px;\n}\n.fc-header {\n  display: flex;\n  align-items: center;\n  gap: 12px;\n  margin-bottom: 24px;\n}\n.fc-title { font-family: var(--font-d); font-size: 24px; flex: 1; }\n\n.deck-tabs {\n  display: flex;\n  gap: 8px;\n  overflow-x: auto;\n  padding-bottom: 4px;\n  margin-bottom: 24px;\n  -webkit-overflow-scrolling: touch;\n  scrollbar-width: none;\n}\n.deck-tabs::-webkit-scrollbar { display: none; }\n\n.deck-tab {\n  flex-shrink: 0;\n  background: var(--card);\n  border: 2px solid var(--border);\n  border-radius: 100px;\n  padding: 8px 18px;\n  font-family: var(--font-b);\n  font-size: 13px;\n  font-weight: 700;\n  color: var(--text2);\n  cursor: pointer;\n  transition: all 0.2s;\n  white-space: nowrap;\n}\n.deck-tab.active {\n  background: var(--orange);\n  border-color: var(--orange);\n  color: white;\n}\n\n/* FLASHCARD */\n.card-area {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  gap: 20px;\n  flex: 1;\n}\n\n.flashcard-wrap {\n  perspective: 1000px;\n  width: min(90vw, 420px);\n  height: min(60vw, 320px);\n  cursor: pointer;\n  flex-shrink: 0;\n}\n.flashcard {\n  width: 100%;\n  height: 100%;\n  position: relative;\n  transform-style: preserve-3d;\n  transition: transform 0.5s cubic-bezier(0.4, 0, 0.2, 1);\n}\n.flashcard.flipped { transform: rotateY(180deg); }\n.fc-face {\n  position: absolute;\n  inset: 0;\n  background: var(--card);\n  border: 3px solid var(--border);\n  border-radius: clamp(16px, 4vw, 28px);\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  gap: clamp(6px, 2vw, 14px);\n  backface-visibility: hidden;\n  box-shadow: var(--shadow);\n  padding: clamp(10px, 3vw, 24px);\n}\n.fc-back { transform: rotateY(180deg); }\n.fc-emoji { font-size: clamp(48px, 14vw, 90px); line-height: 1; }\n.fc-letter {\n  font-family: var(--font-d);\n  font-size: clamp(52px, 16vw, 100px);\n  color: var(--orange);\n  line-height: 1;\n}\n.fc-word {\n  font-family: var(--font-d);\n  font-size: clamp(18px, 5vw, 34px);\n  color: var(--text);\n  text-align: center;\n}\n.fc-is-for {\n  font-family: var(--font-b);\n  font-size: clamp(13px, 3.5vw, 22px);\n  font-weight: 800;\n  color: var(--text2);\n  text-align: center;\n  margin-top: -4px;\n}\n.fc-is-for-back {\n  font-family: var(--font-b);\n  font-size: clamp(13px, 3.5vw, 22px);\n  font-weight: 800;\n  color: var(--text2);\n  text-align: center;\n  margin-top: -4px;\n}\n.fc-hint {\n  font-size: 13px;\n  color: var(--text2);\n  font-weight: 600;\n  display: flex;\n  align-items: center;\n  gap: 6px;\n}\n\n.fc-controls {\n  display: flex;\n  align-items: center;\n  gap: 16px;\n  width: min(90vw, 420px);\n}\n.fc-nav {\n  width: clamp(44px, 12vw, 60px);\n  height: clamp(44px, 12vw, 60px);\n  border-radius: 50%;\n  border: 2.5px solid var(--border);\n  background: var(--card);\n  font-size: clamp(18px, 5vw, 26px);\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  transition: all 0.2s;\n  box-shadow: 0 2px 8px rgba(0,0,0,0.08);\n  flex-shrink: 0;\n}\n.fc-nav:hover { transform: scale(1.1); }\n\n.fc-progress {\n  flex: 1;\n  text-align: center;\n}\n.fc-counter {\n  font-family: var(--font-d);\n  font-size: 18px;\n  color: var(--text2);\n}\n.progress-bar {\n  height: 6px;\n  background: var(--border);\n  border-radius: 10px;\n  margin-top: 6px;\n  overflow: hidden;\n}\n.progress-fill {\n  height: 100%;\n  background: var(--orange);\n  border-radius: 10px;\n  transition: width 0.3s;\n}\n\n.speak-btn {\n  background: var(--orange);\n  color: white;\n  border: none;\n  border-radius: 100px;\n  padding: clamp(12px, 3vw, 16px) clamp(20px, 6vw, 32px);\n  font-family: var(--font-d);\n  font-size: clamp(16px, 4vw, 20px);\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  transition: all 0.2s;\n  box-shadow: 0 4px 15px rgba(255,122,47,0.4);\n}\n.speak-btn:hover { transform: scale(1.05); }\n.speak-btn:active { transform: scale(0.97); }\n\n/* \u2500\u2500 CELEBRATION \u2500\u2500 */\n.celebration-overlay {\n  position: fixed;\n  inset: 0;\n  background: rgba(0,0,0,0.7);\n  z-index: 300;\n  display: none;\n  align-items: center;\n  justify-content: center;\n  backdrop-filter: blur(6px);\n  animation: fadeIn 0.3s ease;\n}\n.celebration-overlay.open { display: flex; }\n@keyframes fadeIn { from{opacity:0} to{opacity:1} }\n\n.celebration-box {\n  background: var(--card);\n  border-radius: 28px;\n  padding: 40px 32px;\n  text-align: center;\n  max-width: 320px;\n  width: 90%;\n  position: relative;\n  overflow: hidden;\n  animation: popIn 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);\n  box-shadow: 0 20px 60px rgba(0,0,0,0.3);\n}\n@keyframes popIn {\n  from { transform: scale(0.5); opacity: 0; }\n  to { transform: scale(1); opacity: 1; }\n}\n\n.confetti-wrap {\n  position: absolute;\n  inset: 0;\n  pointer-events: none;\n  overflow: hidden;\n}\n.confetti-piece {\n  position: absolute;\n  width: 10px;\n  height: 10px;\n  border-radius: 2px;\n  animation: confettiFall linear forwards;\n  top: -20px;\n}\n@keyframes confettiFall {\n  0% { transform: translateY(0) rotate(0deg); opacity: 1; }\n  100% { transform: translateY(400px) rotate(720deg); opacity: 0; }\n}\n\n.celeb-stars {\n  font-size: 28px;\n  margin-bottom: 8px;\n  animation: starPop 0.5s ease 0.2s both;\n}\n@keyframes starPop {\n  from { transform: scale(0); opacity: 0; }\n  to { transform: scale(1); opacity: 1; }\n}\n\n.celeb-emoji {\n  font-size: 72px;\n  margin-bottom: 12px;\n  animation: bounce 1s ease-in-out infinite;\n  display: block;\n}\n\n.celeb-title {\n  font-family: var(--font-d);\n  font-size: 36px;\n  color: var(--orange);\n  margin-bottom: 8px;\n}\n\n.celeb-sub {\n  font-size: 16px;\n  font-weight: 700;\n  color: var(--text2);\n  margin-bottom: 8px;\n}\n\n.celeb-score {\n  font-family: var(--font-d);\n  font-size: 22px;\n  color: var(--green);\n  margin-bottom: 24px;\n  min-height: 28px;\n}\n\n.celeb-btn {\n  width: 100%;\n  padding: 16px;\n  background: var(--orange);\n  color: white;\n  border: none;\n  border-radius: 16px;\n  font-family: var(--font-d);\n  font-size: 20px;\n  cursor: pointer;\n  box-shadow: 0 6px 20px rgba(255,122,47,0.4);\n  transition: transform 0.2s;\n}\n.celeb-btn:hover { transform: scale(1.03); }\n\n@media (max-width: 360px) {\n  .celebration-box { padding: 28px 20px; }\n  .celeb-emoji { font-size: 56px; }\n  .celeb-title { font-size: 28px; }\n}\n\n/* Small phones (< 360px) */\n@media (max-width: 360px) {\n  .mode-grid { grid-template-columns: 1fr 1fr; gap: 10px; }\n  .hero-mascot { font-size: 56px; }\n  .hero-title { font-size: 28px; }\n  .memory-grid { grid-template-columns: repeat(4, 1fr); gap: 6px; }\n  .mem-card { font-size: 22px; }\n}\n\n/* Tablets (768px+) */\n@media (min-width: 768px) {\n  .page-wrap { padding: 32px; }\n  #home { align-items: center; padding: 40px; }\n  .mode-grid { grid-template-columns: repeat(4, 1fr); max-width: 700px; }\n  .flashcard-wrap { width: min(60vw, 480px); height: min(40vw, 360px); }\n  .fc-controls { width: min(60vw, 480px); }\n  .memory-grid { grid-template-columns: repeat(4, 1fr); max-width: 500px; gap: 14px; }\n  .mem-card { font-size: 40px; border-radius: 18px; }\n  .story-cards { max-width: 600px; margin: 0 auto; }\n  .stat-cards { max-width: 600px; margin: 0 auto 24px; }\n  #flashcards, #memory, #stories-list, #reader, #dashboard, #settings {\n    padding: 32px;\n    max-width: 700px;\n    margin: 0 auto;\n    width: 100%;\n  }\n  .card-area { align-items: center; }\n}\n\n/* Large screens / desktop (1024px+) */\n@media (min-width: 1024px) {\n  body { display: flex; justify-content: center; }\n  .screen { max-width: 480px; width: 100%; }\n  .bg-shapes { display: none; }\n  #home { padding: 48px 32px; }\n  .flashcard-wrap { width: 400px; height: 300px; }\n  .fc-controls { width: 400px; }\n}\n\n/* \u2500\u2500 MEMORY GAME \u2500\u2500 */\n#memory {\n  padding: 20px;\n}\n.memory-header {\n  display: flex;\n  align-items: center;\n  gap: 12px;\n  margin-bottom: 20px;\n}\n.memory-title { font-family: var(--font-d); font-size: 24px; flex: 1; }\n.memory-score {\n  font-family: var(--font-d);\n  font-size: 18px;\n  color: var(--orange);\n  background: var(--card);\n  border: 2px solid var(--border);\n  border-radius: 12px;\n  padding: 6px 16px;\n}\n\n.memory-grid {\n  display: grid;\n  grid-template-columns: repeat(4, 1fr);\n  gap: 10px;\n  max-width: 400px;\n  margin: 0 auto 20px;\n}\n\n.mem-card {\n  aspect-ratio: 1;\n  background: var(--orange);\n  border-radius: 14px;\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 32px;\n  transition: all 0.3s;\n  transform-style: preserve-3d;\n  position: relative;\n  box-shadow: 0 3px 10px rgba(255,122,47,0.3);\n}\n.mem-card.revealed { background: var(--card); border: 2.5px solid var(--border); }\n.mem-card.matched { background: var(--green); border: 2.5px solid var(--green); animation: pop 0.3s ease; }\n@keyframes pop { 0%,100%{transform:scale(1)} 50%{transform:scale(1.15)} }\n.mem-card .card-back { display: none; }\n.mem-card.revealed .card-back,\n.mem-card.matched .card-back { display: block; }\n.mem-card .card-front { position: absolute; font-size: 24px; color: white; opacity: 0.4; }\n.mem-card.revealed .card-front,\n.mem-card.matched .card-front { display: none; }\n\n.memory-status {\n  text-align: center;\n  font-family: var(--font-d);\n  font-size: 20px;\n  color: var(--text2);\n}\n\n/* \u2500\u2500 STORIES SCREEN \u2500\u2500 */\n#stories-list {\n  padding: 20px;\n}\n.stories-header {\n  display: flex;\n  align-items: center;\n  gap: 12px;\n  margin-bottom: 24px;\n}\n.stories-title { font-family: var(--font-d); font-size: 24px; flex: 1; }\n\n.story-cards {\n  display: flex;\n  flex-direction: column;\n  gap: 14px;\n}\n\n.story-card {\n  background: var(--card);\n  border: 2.5px solid var(--border);\n  border-radius: var(--radius);\n  padding: 20px;\n  cursor: pointer;\n  transition: all 0.2s;\n  display: flex;\n  align-items: center;\n  gap: 16px;\n  box-shadow: var(--shadow);\n}\n.story-card:hover { transform: translateY(-3px); }\n.story-thumb {\n  font-size: 52px;\n  width: 72px;\n  height: 72px;\n  background: var(--bg2);\n  border-radius: 16px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  flex-shrink: 0;\n}\n.story-info { flex: 1; }\n.story-name { font-family: var(--font-d); font-size: 20px; color: var(--text); margin-bottom: 4px; }\n.story-meta { font-size: 13px; color: var(--text2); font-weight: 600; }\n.story-arrow { font-size: 24px; color: var(--text2); }\n\n/* \u2500\u2500 STORY READER \u2500\u2500 */\n#reader {\n  padding: 20px;\n}\n.reader-header {\n  display: flex;\n  align-items: center;\n  gap: 12px;\n  margin-bottom: 20px;\n}\n.reader-title { font-family: var(--font-d); font-size: 20px; flex: 1; }\n\n.story-scene {\n  background: var(--card);\n  border: 2.5px solid var(--border);\n  border-radius: 24px;\n  padding: 24px;\n  margin-bottom: 20px;\n  box-shadow: var(--shadow);\n  text-align: center;\n}\n.scene-emoji { font-size: 100px; margin-bottom: 16px; display: block; animation: sceneFloat 3s ease-in-out infinite; }\n@keyframes sceneFloat { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-8px)} }\n\n.story-text {\n  font-family: var(--font-b);\n  font-size: 22px;\n  font-weight: 700;\n  color: var(--text);\n  line-height: 1.6;\n  text-align: center;\n}\n.story-text .word {\n  cursor: pointer;\n  border-radius: 6px;\n  padding: 2px 3px;\n  transition: all 0.15s;\n  display: inline-block;\n}\n.story-text .word:hover { background: var(--yellow); }\n.story-text .word.highlight { background: var(--yellow); transform: scale(1.05); }\n\n.reader-controls {\n  display: flex;\n  gap: 12px;\n  margin-bottom: 20px;\n  justify-content: center;\n  flex-wrap: wrap;\n}\n.reader-btn {\n  padding: 12px 22px;\n  border-radius: 100px;\n  border: 2.5px solid var(--border);\n  background: var(--card);\n  font-family: var(--font-b);\n  font-size: 14px;\n  font-weight: 800;\n  color: var(--text);\n  cursor: pointer;\n  transition: all 0.2s;\n  display: flex;\n  align-items: center;\n  gap: 8px;\n}\n.reader-btn.primary {\n  background: var(--orange);\n  border-color: var(--orange);\n  color: white;\n  box-shadow: 0 4px 15px rgba(255,122,47,0.4);\n}\n.reader-btn:hover { transform: scale(1.05); }\n\n.page-dots {\n  display: flex;\n  justify-content: center;\n  gap: 8px;\n  margin-bottom: 20px;\n}\n.page-dot {\n  width: 10px;\n  height: 10px;\n  border-radius: 50%;\n  background: var(--border);\n  transition: all 0.3s;\n  cursor: pointer;\n}\n.page-dot.active {\n  background: var(--orange);\n  width: 24px;\n  border-radius: 10px;\n}\n\n.reader-nav {\n  display: flex;\n  gap: 12px;\n  justify-content: center;\n}\n.reader-nav-btn {\n  flex: 1;\n  max-width: 160px;\n  padding: 14px;\n  border-radius: 16px;\n  border: 2.5px solid var(--border);\n  background: var(--card);\n  font-family: var(--font-d);\n  font-size: 16px;\n  color: var(--text);\n  cursor: pointer;\n  transition: all 0.2s;\n  text-align: center;\n}\n.reader-nav-btn:hover { border-color: var(--orange); color: var(--orange); }\n.reader-nav-btn.next {\n  background: var(--orange);\n  border-color: var(--orange);\n  color: white;\n}\n\n/* \u2500\u2500 PARENT DASHBOARD \u2500\u2500 */\n#dashboard {\n  padding: 20px;\n}\n.dash-header {\n  display: flex;\n  align-items: center;\n  gap: 12px;\n  margin-bottom: 24px;\n}\n.dash-title { font-family: var(--font-d); font-size: 24px; flex: 1; }\n\n.stat-cards {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 12px;\n  margin-bottom: 24px;\n}\n.stat-card {\n  background: var(--card);\n  border: 2.5px solid var(--border);\n  border-radius: 18px;\n  padding: 18px;\n  box-shadow: var(--shadow);\n}\n.stat-card-icon { font-size: 28px; margin-bottom: 8px; }\n.stat-card-val {\n  font-family: var(--font-d);\n  font-size: 32px;\n  color: var(--orange);\n  line-height: 1;\n  margin-bottom: 4px;\n}\n.stat-card-label { font-size: 12px; font-weight: 700; color: var(--text2); text-transform: uppercase; letter-spacing: 0.06em; }\n\n.activity-title { font-family: var(--font-d); font-size: 20px; margin-bottom: 12px; }\n.activity-list { display: flex; flex-direction: column; gap: 8px; }\n.activity-item {\n  background: var(--card);\n  border: 2px solid var(--border);\n  border-radius: 14px;\n  padding: 14px 16px;\n  display: flex;\n  align-items: center;\n  gap: 12px;\n}\n.activity-icon { font-size: 24px; }\n.activity-info { flex: 1; }\n.activity-name { font-weight: 700; font-size: 14px; color: var(--text); }\n.activity-time { font-size: 12px; color: var(--text2); }\n.activity-score { font-family: var(--font-d); font-size: 16px; color: var(--green); }\n\n/* \u2500\u2500 PREMIUM MODAL \u2500\u2500 */\n.modal-overlay {\n  position: fixed;\n  inset: 0;\n  background: rgba(0,0,0,0.5);\n  z-index: 100;\n  display: none;\n  align-items: flex-end;\n  justify-content: center;\n  backdrop-filter: blur(4px);\n}\n.modal-overlay.open { display: flex; }\n.modal {\n  background: var(--card);\n  border-radius: 28px 28px 0 0;\n  padding: 32px 24px 48px;\n  width: 100%;\n  max-width: 500px;\n  animation: slideUp 0.3s ease;\n}\n@keyframes slideUp { from{transform:translateY(100%)} to{transform:translateY(0)} }\n.modal-handle { width: 40px; height: 4px; background: var(--border); border-radius: 10px; margin: 0 auto 24px; }\n.modal-title { font-family: var(--font-d); font-size: 28px; text-align: center; margin-bottom: 8px; }\n.modal-sub { font-size: 15px; color: var(--text2); text-align: center; margin-bottom: 24px; font-weight: 600; }\n.modal-features { display: flex; flex-direction: column; gap: 10px; margin-bottom: 28px; }\n.modal-feature { display: flex; align-items: center; gap: 12px; font-size: 15px; font-weight: 700; }\n.modal-feature-icon { font-size: 22px; }\n.modal-price {\n  text-align: center;\n  font-family: var(--font-d);\n  font-size: 14px;\n  color: var(--text2);\n  margin-bottom: 16px;\n}\n.modal-price strong { font-size: 36px; color: var(--orange); }\n.modal-cta {\n  width: 100%;\n  padding: 18px;\n  background: var(--orange);\n  color: white;\n  border: none;\n  border-radius: 16px;\n  font-family: var(--font-d);\n  font-size: 20px;\n  cursor: pointer;\n  box-shadow: 0 6px 20px rgba(255,122,47,0.4);\n  transition: all 0.2s;\n  margin-bottom: 12px;\n}\n.modal-cta:hover { transform: scale(1.02); }\n.modal-close {\n  width: 100%;\n  padding: 14px;\n  background: transparent;\n  color: var(--text2);\n  border: none;\n  font-family: var(--font-b);\n  font-size: 14px;\n  font-weight: 700;\n  cursor: pointer;\n}\n\n/* \u2500\u2500 COMPLETION TOAST \u2500\u2500 */\n.toast {\n  position: fixed;\n  bottom: 24px;\n  left: 50%;\n  transform: translateX(-50%) translateY(100px);\n  background: var(--green);\n  color: white;\n  font-family: var(--font-d);\n  font-size: 18px;\n  padding: 14px 28px;\n  border-radius: 100px;\n  z-index: 200;\n  transition: transform 0.3s;\n  white-space: nowrap;\n  box-shadow: 0 4px 20px rgba(6,214,160,0.4);\n}\n.toast.show { transform: translateX(-50%) translateY(0); }\n\n/* \u2500\u2500 SETTINGS SCREEN \u2500\u2500 */\n#settings {\n  padding: 20px;\n}\n.settings-header {\n  display: flex;\n  align-items: center;\n  gap: 12px;\n  margin-bottom: 24px;\n}\n.settings-title { font-family: var(--font-d); font-size: 24px; flex: 1; }\n.settings-section { margin-bottom: 24px; }\n.settings-section-title { font-family: var(--font-d); font-size: 18px; margin-bottom: 12px; color: var(--text2); }\n.setting-row {\n  background: var(--card);\n  border: 2px solid var(--border);\n  border-radius: 14px;\n  padding: 16px 18px;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  margin-bottom: 8px;\n}\n.setting-info { }\n.setting-name { font-weight: 700; font-size: 15px; color: var(--text); }\n.setting-desc { font-size: 12px; color: var(--text2); margin-top: 2px; }\n.toggle {\n  width: 50px;\n  height: 28px;\n  background: var(--border);\n  border-radius: 100px;\n  position: relative;\n  cursor: pointer;\n  transition: background 0.3s;\n  flex-shrink: 0;\n}\n.toggle.on { background: var(--green); }\n.toggle::after {\n  content: '';\n  position: absolute;\n  width: 22px;\n  height: 22px;\n  background: white;\n  border-radius: 50%;\n  top: 3px;\n  left: 3px;\n  transition: transform 0.3s;\n  box-shadow: 0 2px 6px rgba(0,0,0,0.2);\n}\n.toggle.on::after { transform: translateX(22px); }\n\n\n</style>\n</head>\n<body>\n\n<div class=\"bg-shapes\">\n  <div class=\"shape shape-1\"></div>\n  <div class=\"shape shape-2\"></div>\n  <div class=\"shape shape-3\"></div>\n</div>\n\n<!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 HOME \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n<div class=\"screen active\" id=\"home\">\n  <div class=\"home-header\">\n    <div class=\"logo\">Kiddo<span>Learn</span></div>\n    <div class=\"header-btns\">\n      <button class=\"icon-btn\" onclick=\"showScreen('settings')\" title=\"Settings\">\u2699\ufe0f</button>\n      <button class=\"icon-btn\" onclick=\"showScreen('dashboard')\" title=\"Parent Dashboard\">\ud83d\udc68\u200d\ud83d\udc69\u200d\ud83d\udc67</button>\n    </div>\n  </div>\n\n  <div class=\"hero-mascot\">\ud83e\udd81</div>\n  <div class=\"hero-title\">Learn & Read!</div>\n  <div class=\"hero-sub\">Tap a mode to start learning \ud83c\udf1f</div>\n\n  <div class=\"section-title\">Choose Activity</div>\n  <div class=\"mode-grid\">\n    <div class=\"mode-card orange\" onclick=\"showScreen('flashcards')\">\n      <span class=\"mode-emoji\">\ud83c\udccf</span>\n      <div class=\"mode-name\">Flashcards</div>\n      <div class=\"mode-desc\">Letters, numbers & more</div>\n    </div>\n    <div class=\"mode-card blue\" onclick=\"startMemory()\">\n      <span class=\"mode-emoji\">\ud83e\udde0</span>\n      <div class=\"mode-name\">Memory</div>\n      <div class=\"mode-desc\">Match the cards!</div>\n    </div>\n    <div class=\"mode-card green\" onclick=\"showScreen('stories-list')\">\n      <span class=\"mode-emoji\">\ud83d\udcd6</span>\n      <div class=\"mode-name\">Stories</div>\n      <div class=\"mode-desc\">Read-aloud tales</div>\n      <div class=\"mode-badge\">NEW</div>\n    </div>\n    <div class=\"mode-card purple\" onclick=\"showPremium()\">\n      <span class=\"mode-emoji\">\u2b50</span>\n      <div class=\"mode-name\">All Access</div>\n      <div class=\"mode-desc\">Unlock everything</div>\n      <div class=\"mode-badge\">PRO</div>\n    </div>\n  </div>\n\n  <div class=\"streak-bar\">\n    <div class=\"streak-icon\">\ud83d\udd25</div>\n    <div class=\"streak-info\">\n      <div class=\"streak-label\">Day Streak</div>\n      <div class=\"streak-val\" id=\"streak-display\">3 days</div>\n    </div>\n    <div class=\"streak-dots\" id=\"streak-dots\"></div>\n  </div>\n</div>\n\n<!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 FLASHCARDS \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n<div class=\"screen\" id=\"flashcards\">\n  <div class=\"fc-header\">\n    <button class=\"back-btn\" onclick=\"showScreen('home')\">\u2190 Back</button>\n    <div class=\"fc-title\">Flashcards</div>\n  </div>\n\n  <div class=\"deck-tabs\" id=\"deck-tabs\"></div>\n\n  <div class=\"card-area\">\n    <div class=\"flashcard-wrap\" onclick=\"flipCard()\">\n      <div class=\"flashcard\" id=\"flashcard\">\n        <div class=\"fc-face fc-front\">\n          <div class=\"fc-emoji\" id=\"fc-front-emoji\">\ud83c\udf4e</div>\n          <div class=\"fc-word\" id=\"fc-front-word\">Apple</div>\n          <div class=\"fc-is-for\" id=\"fc-is-for\">A is for Apple</div>\n          <div class=\"fc-hint\">\ud83d\udc46 Tap to see the letter</div>\n        </div>\n        <div class=\"fc-face fc-back\">\n          <div class=\"fc-letter\" id=\"fc-back-letter\">A</div>\n          <div class=\"fc-is-for-back\" id=\"fc-is-for-back\">is for Apple</div>\n        </div>\n      </div>\n    </div>\n\n    <div class=\"fc-controls\">\n      <button class=\"fc-nav\" onclick=\"prevCard()\">\u25c0</button>\n      <div class=\"fc-progress\">\n        <div class=\"fc-counter\" id=\"fc-counter\">1 / 10</div>\n        <div class=\"progress-bar\"><div class=\"progress-fill\" id=\"fc-progress\" style=\"width:10%\"></div></div>\n      </div>\n      <button class=\"fc-nav\" onclick=\"nextCard()\">\u25b6</button>\n    </div>\n\n    <button class=\"speak-btn\" onclick=\"speakCurrentCard()\">\n      \ud83d\udd0a Hear it!\n    </button>\n  </div>\n</div>\n\n<!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 MEMORY GAME \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n<div class=\"screen\" id=\"memory\">\n  <div class=\"memory-header\">\n    <button class=\"back-btn\" onclick=\"showScreen('home')\">\u2190 Back</button>\n    <div class=\"memory-title\">Memory Match</div>\n    <div class=\"memory-score\">\ud83c\udfc6 <span id=\"match-score\">0</span></div>\n  </div>\n\n  <div class=\"memory-grid\" id=\"memory-grid\"></div>\n  <div class=\"memory-status\" id=\"memory-status\">Find all the matching pairs! \ud83c\udfaf</div>\n  <div style=\"text-align:center;margin-top:16px\">\n    <button class=\"reader-btn primary\" onclick=\"startMemory()\" style=\"display:inline-flex\">\ud83d\udd04 New Game</button>\n  </div>\n</div>\n\n<!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 STORIES LIST \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n<div class=\"screen\" id=\"stories-list\">\n  <div class=\"stories-header\">\n    <button class=\"back-btn\" onclick=\"showScreen('home')\">\u2190 Back</button>\n    <div class=\"stories-title\">Storybooks \ud83d\udcd6</div>\n  </div>\n\n  <div class=\"story-cards\" id=\"story-cards\"></div>\n</div>\n\n<!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 STORY READER \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n<div class=\"screen\" id=\"reader\">\n  <div class=\"reader-header\">\n    <button class=\"back-btn\" onclick=\"showScreen('stories-list')\">\u2190 Back</button>\n    <div class=\"reader-title\" id=\"reader-title\">The Lion's Big Day</div>\n  </div>\n\n  <div class=\"story-scene\">\n    <span class=\"scene-emoji\" id=\"scene-emoji\">\ud83e\udd81</span>\n    <div class=\"story-text\" id=\"story-text\"></div>\n  </div>\n\n  <div class=\"page-dots\" id=\"page-dots\"></div>\n\n  <div class=\"reader-controls\">\n    <button class=\"reader-btn primary\" onclick=\"readAloud()\">\ud83d\udd0a Read Aloud</button>\n    <button class=\"reader-btn\" onclick=\"stopReading()\">\u23f9 Stop</button>\n  </div>\n\n  <div class=\"reader-nav\">\n    <button class=\"reader-nav-btn\" id=\"prev-page-btn\" onclick=\"prevPage()\">\u25c0 Prev</button>\n    <button class=\"reader-nav-btn next\" id=\"next-page-btn\" onclick=\"nextPage()\">Next \u25b6</button>\n  </div>\n</div>\n\n<!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 DASHBOARD \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n<div class=\"screen\" id=\"dashboard\">\n  <div class=\"dash-header\">\n    <button class=\"back-btn\" onclick=\"showScreen('home')\">\u2190 Back</button>\n    <div class=\"dash-title\">Parent Dashboard \ud83d\udc68\u200d\ud83d\udc69\u200d\ud83d\udc67</div>\n  </div>\n\n  <div class=\"stat-cards\">\n    <div class=\"stat-card\">\n      <div class=\"stat-card-icon\">\u23f1\ufe0f</div>\n      <div class=\"stat-card-val\" id=\"stat-time\">12</div>\n      <div class=\"stat-card-label\">Minutes Today</div>\n    </div>\n    <div class=\"stat-card\">\n      <div class=\"stat-card-icon\">\ud83c\udccf</div>\n      <div class=\"stat-card-val\" id=\"stat-cards\">47</div>\n      <div class=\"stat-card-label\">Cards Learned</div>\n    </div>\n    <div class=\"stat-card\">\n      <div class=\"stat-card-icon\">\ud83d\udcd6</div>\n      <div class=\"stat-card-val\" id=\"stat-stories\">3</div>\n      <div class=\"stat-card-label\">Stories Read</div>\n    </div>\n    <div class=\"stat-card\">\n      <div class=\"stat-card-icon\">\ud83d\udd25</div>\n      <div class=\"stat-card-val\" id=\"stat-streak\">3</div>\n      <div class=\"stat-card-label\">Day Streak</div>\n    </div>\n  </div>\n\n  <div class=\"activity-title\">Recent Activity</div>\n  <div class=\"activity-list\" id=\"activity-list\"></div>\n</div>\n\n<!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 SETTINGS \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n<div class=\"screen\" id=\"settings\">\n  <div class=\"settings-header\">\n    <button class=\"back-btn\" onclick=\"showScreen('home')\">\u2190 Back</button>\n    <div class=\"settings-title\">Settings \u2699\ufe0f</div>\n  </div>\n\n  <div class=\"settings-section\">\n    <div class=\"settings-section-title\">Learning</div>\n    <div class=\"setting-row\">\n      <div class=\"setting-info\">\n        <div class=\"setting-name\">Auto Read Aloud</div>\n        <div class=\"setting-desc\">Speak each card automatically</div>\n      </div>\n      <div class=\"toggle on\" id=\"toggle-autoread\" onclick=\"toggleSetting('autoread')\"></div>\n    </div>\n    <div class=\"setting-row\">\n      <div class=\"setting-info\">\n        <div class=\"setting-name\">Sound Effects</div>\n        <div class=\"setting-desc\">Play sounds on actions</div>\n      </div>\n      <div class=\"toggle on\" id=\"toggle-sounds\" onclick=\"toggleSetting('sounds')\"></div>\n    </div>\n  </div>\n\n  <div class=\"settings-section\">\n    <div class=\"settings-section-title\">Display</div>\n    <div class=\"setting-row\">\n      <div class=\"setting-info\">\n        <div class=\"setting-name\">Bedtime Mode</div>\n        <div class=\"setting-desc\">Soft colors for nighttime</div>\n      </div>\n      <div class=\"toggle\" id=\"toggle-bedtime\" onclick=\"toggleSetting('bedtime')\"></div>\n    </div>\n  </div>\n\n  <div class=\"settings-section\">\n    <div class=\"settings-section-title\">About</div>\n    <div class=\"setting-row\">\n      <div class=\"setting-info\">\n        <div class=\"setting-name\">MAZE KIDS</div>\n        <div class=\"setting-desc\">Version 1.0 \u00b7 Made with \u2764\ufe0f for little learners</div>\n      </div>\n    </div>\n    <div class=\"setting-row\" onclick=\"showPremium()\" style=\"cursor:pointer\">\n      <div class=\"setting-info\">\n        <div class=\"setting-name\">\ud83c\udf1f Upgrade to Premium</div>\n        <div class=\"setting-desc\">Unlock all decks, stories & more</div>\n      </div>\n      <div style=\"color:var(--orange);font-size:20px\">\u203a</div>\n    </div>\n  </div>\n</div>\n\n<!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 PREMIUM MODAL \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n<div class=\"modal-overlay\" id=\"premium-modal\" onclick=\"closePremium(event)\">\n  <div class=\"modal\">\n    <div class=\"modal-handle\"></div>\n    <div style=\"font-size:48px;text-align:center;margin-bottom:12px\">\u2b50</div>\n    <div class=\"modal-title\">Go Premium!</div>\n    <div class=\"modal-sub\">Unlock the full MAZE KIDS experience</div>\n    <div class=\"modal-features\">\n      <div class=\"modal-feature\"><span class=\"modal-feature-icon\">\ud83c\udccf</span> All 8 flashcard decks (500+ cards)</div>\n      <div class=\"modal-feature\"><span class=\"modal-feature-icon\">\ud83d\udcd6</span> All 15 storybooks with narration</div>\n      <div class=\"modal-feature\"><span class=\"modal-feature-icon\">\ud83e\udde0</span> All mini-games unlocked</div>\n      <div class=\"modal-feature\"><span class=\"modal-feature-icon\">\ud83d\udcca</span> Full parent dashboard & reports</div>\n      <div class=\"modal-feature\"><span class=\"modal-feature-icon\">\ud83c\udf19</span> Bedtime mode & calm audio</div>\n      <div class=\"modal-feature\"><span class=\"modal-feature-icon\">\ud83d\udcf5</span> 100% ad-free, forever</div>\n    </div>\n    <div class=\"modal-price\">Just <strong>$3.99</strong>/month \u00b7 Cancel anytime</div>\n    <button class=\"modal-cta\" onclick=\"unlockPremium()\">\ud83d\ude80 Start Free Trial</button>\n    <button class=\"modal-close\" onclick=\"closePremium()\">Maybe later</button>\n  </div>\n</div>\n\n<!-- Toast -->\n<div class=\"toast\" id=\"toast\">\ud83c\udf89 Great job!</div>\n\n<script>\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// DATA\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nconst DECKS = {\n  Letters: [\n    {front:'A', emoji:'\ud83c\udf4e', word:'Apple'},\n    {front:'B', emoji:'\ud83d\udc3b', word:'Bear'},\n    {front:'C', emoji:'\ud83d\udc31', word:'Cat'},\n    {front:'D', emoji:'\ud83d\udc36', word:'Dog'},\n    {front:'E', emoji:'\ud83e\udd5a', word:'Egg'},\n    {front:'F', emoji:'\ud83d\udc38', word:'Frog'},\n    {front:'G', emoji:'\ud83c\udf47', word:'Grape'},\n    {front:'H', emoji:'\ud83c\udfe0', word:'House'},\n    {front:'I', emoji:'\ud83c\udf66', word:'Ice Cream'},\n    {front:'J', emoji:'\ud83e\uddc3', word:'Juice'},\n    {front:'K', emoji:'\ud83e\ude81', word:'Kite'},\n    {front:'L', emoji:'\ud83e\udd81', word:'Lion'},\n    {front:'M', emoji:'\ud83c\udf19', word:'Moon'},\n    {front:'N', emoji:'\ud83e\udeba', word:'Nest'},\n    {front:'O', emoji:'\ud83e\udd89', word:'Owl'},\n    {front:'P', emoji:'\ud83d\udc27', word:'Penguin'},\n    {front:'Q', emoji:'\ud83d\udc51', word:'Queen'},\n    {front:'R', emoji:'\ud83c\udf08', word:'Rainbow'},\n    {front:'S', emoji:'\u2b50', word:'Star'},\n    {front:'T', emoji:'\ud83d\udc22', word:'Turtle'},\n    {front:'U', emoji:'\u2602\ufe0f', word:'Umbrella'},\n    {front:'V', emoji:'\ud83c\udfbb', word:'Violin'},\n    {front:'W', emoji:'\ud83d\udc0b', word:'Whale'},\n    {front:'X', emoji:'\ud83c\udf84', word:'Xmas Tree'},\n    {front:'Y', emoji:'\ud83e\ude80', word:'Yo-yo'},\n    {front:'Z', emoji:'\ud83e\udd93', word:'Zebra'},\n  ],\n  Counting: [\n    {front:'1', emoji:'\ud83c\udf1f', word:'One'},\n    {front:'2', emoji:'\ud83d\udc40', word:'Two'},\n    {front:'3', emoji:'\ud83c\udf40', word:'Three'},\n    {front:'4', emoji:'\ud83d\udc3e', word:'Four'},\n    {front:'5', emoji:'\u270b', word:'Five'},\n    {front:'6', emoji:'\ud83c\udfb2', word:'Six'},\n    {front:'7', emoji:'\ud83c\udf08', word:'Seven'},\n    {front:'8', emoji:'\ud83d\udc19', word:'Eight'},\n    {front:'9', emoji:'\ud83c\udf88', word:'Nine'},\n    {front:'10', emoji:'\ud83d\udd1f', word:'Ten'},\n  ],\n  Shapes: [\n    {front:'\u2b55', emoji:'\u2b55', word:'Circle'},\n    {front:'\ud83d\udd37', emoji:'\ud83d\udd37', word:'Diamond'},\n    {front:'\u2764\ufe0f', emoji:'\u2764\ufe0f', word:'Heart'},\n    {front:'\u2b1b', emoji:'\u2b1b', word:'Square'},\n    {front:'\ud83d\udd3a', emoji:'\ud83d\udd3a', word:'Triangle'},\n    {front:'\u25ac', emoji:'\ud83d\udcc4', word:'Rectangle'},\n    {front:'\u2b50', emoji:'\u2b50', word:'Star'},\n    {front:'\ud83e\udd5a', emoji:'\ud83e\udd5a', word:'Oval'},\n  ],\n  Colors: [\n    {front:'\ud83d\udd34', emoji:'\ud83c\udf4e', word:'Red'},\n    {front:'\ud83d\udd35', emoji:'\ud83e\uded0', word:'Blue'},\n    {front:'\ud83d\udfe2', emoji:'\ud83c\udf40', word:'Green'},\n    {front:'\ud83d\udfe1', emoji:'\u2b50', word:'Yellow'},\n    {front:'\ud83d\udfe0', emoji:'\ud83c\udf4a', word:'Orange'},\n    {front:'\ud83d\udfe3', emoji:'\ud83c\udf47', word:'Purple'},\n    {front:'\u26ab', emoji:'\ud83d\udda4', word:'Black'},\n    {front:'\u26aa', emoji:'\ud83d\udc11', word:'White'},\n    {front:'\ud83e\ude77', emoji:'\ud83c\udf38', word:'Pink'},\n    {front:'\ud83d\udfe4', emoji:'\ud83d\udc3b', word:'Brown'},\n  ],\n  Animals: [\n    {front:'\ud83e\udd81', emoji:'\ud83e\udd81', word:'Lion'},\n    {front:'\ud83d\udc18', emoji:'\ud83d\udc18', word:'Elephant'},\n    {front:'\ud83e\udd92', emoji:'\ud83e\udd92', word:'Giraffe'},\n    {front:'\ud83d\udc27', emoji:'\ud83d\udc27', word:'Penguin'},\n    {front:'\ud83e\udd8a', emoji:'\ud83e\udd8a', word:'Fox'},\n    {front:'\ud83d\udc2c', emoji:'\ud83d\udc2c', word:'Dolphin'},\n    {front:'\ud83e\udd8b', emoji:'\ud83e\udd8b', word:'Butterfly'},\n    {front:'\ud83d\udc22', emoji:'\ud83d\udc22', word:'Turtle'},\n    {front:'\ud83e\udd89', emoji:'\ud83e\udd89', word:'Owl'},\n    {front:'\ud83d\udc28', emoji:'\ud83d\udc28', word:'Koala'},\n  ],\n  Colors: [\n    {front:'\ud83d\udd34', emoji:'\ud83c\udf4e', word:'Red'},\n    {front:'\ud83d\udd35', emoji:'\ud83e\uded0', word:'Blue'},\n    {front:'\ud83d\udfe2', emoji:'\ud83c\udf40', word:'Green'},\n    {front:'\ud83d\udfe1', emoji:'\u2b50', word:'Yellow'},\n    {front:'\ud83d\udfe0', emoji:'\ud83c\udf4a', word:'Orange'},\n    {front:'\ud83d\udfe3', emoji:'\ud83c\udf47', word:'Purple'},\n    {front:'\u26ab', emoji:'\ud83d\udc26\u200d\u2b1b', word:'Black'},\n    {front:'\u26aa', emoji:'\ud83d\udc11', word:'White'},\n    {front:'\ud83e\ude77', emoji:'\ud83c\udf38', word:'Pink'},\n    {front:'\ud83d\udfe4', emoji:'\ud83d\udc3b', word:'Brown'},\n  ],\n  Shapes: [\n    {front:'\u2b55', emoji:'\ud83c\udf55', word:'Circle'},\n    {front:'\ud83d\udfe5', emoji:'\ud83d\udce6', word:'Square'},\n    {front:'\ud83d\udd3a', emoji:'\ud83c\udfd4\ufe0f', word:'Triangle'},\n    {front:'\u25ac', emoji:'\ud83d\udcf1', word:'Rectangle'},\n    {front:'\u2b50', emoji:'\ud83c\udf1f', word:'Star'},\n    {front:'\ud83e\udec0', emoji:'\ud83d\udc9d', word:'Heart'},\n    {front:'\ud83d\udd37', emoji:'\ud83d\udc8e', word:'Diamond'},\n    {front:'\ud83d\udd36', emoji:'\ud83e\ude81', word:'Oval'},\n    {front:'\u2b21', emoji:'\ud83c\udf6f', word:'Hexagon'},\n    {front:'\ud83c\udf19', emoji:'\ud83c\udf19', word:'Crescent'},\n  ],\n};\n\nconst STORIES = [\n  {\n    id: 0,\n    name: \"The Lion's Big Day\",\n    emoji: '\ud83e\udd81',\n    age: '3-5 years',\n    pages: [\n      { emoji: '\ud83e\udd81', text: 'Leo the lion woke up one bright morning.' },\n      { emoji: '\u2600\ufe0f', text: 'The sun was warm and golden in the sky.' },\n      { emoji: '\ud83c\udf3f', text: 'Leo walked through the tall green grass.' },\n      { emoji: '\ud83e\udd81\ud83d\udc18', text: 'He met his friend Ella the elephant.' },\n      { emoji: '\ud83d\udca7', text: 'They walked together to the cool blue river.' },\n      { emoji: '\ud83c\udf89', text: 'It was the best day ever for Leo!' },\n    ]\n  },\n  {\n    id: 1,\n    name: \"Benny Finds a Star\",\n    emoji: '\u2b50',\n    age: '4-6 years',\n    pages: [\n      { emoji: '\ud83d\udc3b', text: 'Benny the bear looked up at the dark night sky.' },\n      { emoji: '\u2b50', text: 'One little star was falling down, down, down.' },\n      { emoji: '\ud83c\udf3f', text: 'It landed softly in the meadow near his home.' },\n      { emoji: '\u2728', text: 'The star glowed and sparkled with magic light.' },\n      { emoji: '\ud83d\udc3b\u2b50', text: 'Benny held the star gently in his big paws.' },\n      { emoji: '\ud83c\udf19', text: 'He placed it back up high where it belonged.' },\n    ]\n  },\n  {\n    id: 2,\n    name: \"The Rainbow Bridge\",\n    emoji: '\ud83c\udf08',\n    age: '3-5 years',\n    pages: [\n      { emoji: '\ud83c\udf27\ufe0f', text: 'It rained all morning in the little town.' },\n      { emoji: '\ud83d\udc38', text: 'Fiona the frog danced in every puddle.' },\n      { emoji: '\u2600\ufe0f', text: 'Then the sun came out from behind the clouds.' },\n      { emoji: '\ud83c\udf08', text: 'A beautiful rainbow stretched across the sky.' },\n      { emoji: '\ud83d\udc38\ud83e\udd8b', text: 'Fiona and her friends ran to find the end.' },\n      { emoji: '\ud83c\udf40', text: 'They found a field of lucky clovers instead!' },\n    ]\n  },\n];\n\nconst MEMORY_EMOJIS = ['\ud83e\udd81','\ud83d\udc18','\ud83e\udd92','\ud83d\udc27','\ud83e\udd8a','\ud83d\udc2c','\ud83e\udd8b','\ud83d\udc22'];\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// STATE\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nlet currentDeck = 'Letters';\nlet currentCardIndex = 0;\nlet isFlipped = false;\nlet currentStory = null;\nlet currentPage = 0;\nlet isSpeaking = false;\nlet memCards = [];\nlet revealed = [];\nlet matched = [];\nlet lockBoard = false;\nlet matchScore = 0;\nlet settings = { autoread: true, sounds: true, bedtime: false };\nlet stats = { time: 12, cards: 47, stories: 3, streak: 3 };\nlet activities = [\n  { icon: '\ud83c\udccf', name: 'Flashcards - Letters', time: 'Today, 3:45 PM', score: '10/10' },\n  { icon: '\ud83e\udde0', name: 'Memory Match', time: 'Today, 3:30 PM', score: '8 pairs' },\n  { icon: '\ud83d\udcd6', name: \"The Lion's Big Day\", time: 'Yesterday', score: '\u2b50\u2b50\u2b50' },\n];\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// NAVIGATION\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nfunction showScreen(id) {\n  document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));\n  document.getElementById(id).classList.add('active');\n  window.scrollTo(0, 0);\n}\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// FLASHCARDS\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nfunction initFlashcards() {\n  // Build tabs\n  const tabs = document.getElementById('deck-tabs');\n  tabs.innerHTML = '';\n  Object.keys(DECKS).forEach(deck => {\n    const tab = document.createElement('button');\n    tab.className = 'deck-tab' + (deck === currentDeck ? ' active' : '');\n    tab.textContent = deck;\n    tab.onclick = () => selectDeck(deck);\n    tabs.appendChild(tab);\n  });\n  renderCard();\n}\n\nfunction selectDeck(deck) {\n  currentDeck = deck;\n  currentCardIndex = 0;\n  isFlipped = false;\n  document.querySelectorAll('.deck-tab').forEach(t => t.classList.toggle('active', t.textContent === deck));\n  renderCard();\n}\n\nfunction renderCard() {\n  const deck = DECKS[currentDeck];\n  const card = deck[currentCardIndex];\n  const fc = document.getElementById('flashcard');\n  fc.classList.remove('flipped');\n  isFlipped = false;\n\n  // FRONT \u2014 show the product (emoji + word)\n  document.getElementById('fc-front-emoji').textContent = card.emoji;\n  document.getElementById('fc-front-word').textContent = card.word;\n\n  const isForEl = document.getElementById('fc-is-for');\n  if (currentDeck === 'Letters') {\n    isForEl.textContent = `${card.front} is for ${card.word}`;\n  } else if (currentDeck === 'Numbers') {\n    isForEl.textContent = card.word;\n  } else if (currentDeck === 'Shapes') {\n    isForEl.textContent = `This is a ${card.word}`;\n  } else {\n    isForEl.textContent = card.word;\n  }\n\n  // BACK \u2014 show the letter/number\n  const backLetter = document.getElementById('fc-back-letter');\n  backLetter.textContent = card.front;\n  backLetter.style.fontSize = currentDeck === 'Animals' || currentDeck === 'Colors' ? '64px' : '80px';\n\n  const isForBack = document.getElementById('fc-is-for-back');\n  if (currentDeck === 'Letters') {\n    isForBack.textContent = `is for ${card.word}`;\n  } else {\n    isForBack.textContent = card.word;\n  }\n\n  // Counter\n  document.getElementById('fc-counter').textContent = `${currentCardIndex + 1} / ${deck.length}`;\n  document.getElementById('fc-progress').style.width = `${((currentCardIndex + 1) / deck.length) * 100}%`;\n\n  if (settings.autoread) setTimeout(() => speakTeacher(buildPhrase(card)), 400);\n}\n\nfunction flipCard() {\n  const fc = document.getElementById('flashcard');\n  isFlipped = !isFlipped;\n  fc.classList.toggle('flipped', isFlipped);\n  if (isFlipped) {\n    const card = DECKS[currentDeck][currentCardIndex];\n    speak(card.word);\n  }\n}\n\nfunction nextCard() {\n  const deck = DECKS[currentDeck];\n  const isLast = currentCardIndex === deck.length - 1;\n  currentCardIndex = (currentCardIndex + 1) % deck.length;\n  if (isLast) {\n    showCelebration({\n      emoji: '\ud83c\udf93',\n      title: 'You Did It!',\n      sub: `${currentDeck} deck complete!`,\n      score: `${deck.length} cards learned! \u2b50`\n    });\n  }\n  renderCard();\n  stats.cards++;\n}\n\nfunction prevCard() {\n  const deck = DECKS[currentDeck];\n  currentCardIndex = (currentCardIndex - 1 + deck.length) % deck.length;\n  renderCard();\n}\n\nfunction speakCurrentCard() {\n  const card = DECKS[currentDeck][currentCardIndex];\n  speak(card.word);\n}\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// MEMORY GAME\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nfunction startMemory() {\n  showScreen('memory');\n  matchScore = 0;\n  revealed = [];\n  matched = [];\n  lockBoard = false;\n  document.getElementById('match-score').textContent = '0';\n  document.getElementById('memory-status').textContent = 'Find all the matching pairs! \ud83c\udfaf';\n\n  const pairs = [...MEMORY_EMOJIS, ...MEMORY_EMOJIS];\n  memCards = pairs.sort(() => Math.random() - 0.5);\n\n  const grid = document.getElementById('memory-grid');\n  grid.innerHTML = '';\n  memCards.forEach((emoji, i) => {\n    const card = document.createElement('div');\n    card.className = 'mem-card';\n    card.dataset.index = i;\n    card.innerHTML = `<span class=\"card-front\">?</span><span class=\"card-back\">${emoji}</span>`;\n    card.onclick = () => revealCard(i, card);\n    grid.appendChild(card);\n  });\n}\n\nfunction revealCard(index, el) {\n  if (lockBoard || matched.includes(index) || revealed.includes(index)) return;\n  el.classList.add('revealed');\n  revealed.push(index);\n\n  if (revealed.length === 2) {\n    lockBoard = true;\n    const [a, b] = revealed;\n    if (memCards[a] === memCards[b]) {\n      matched.push(a, b);\n      matchScore++;\n      document.getElementById('match-score').textContent = matchScore;\n      document.querySelectorAll('.mem-card')[a].classList.add('matched');\n      document.querySelectorAll('.mem-card')[b].classList.add('matched');\n      revealed = [];\n      lockBoard = false;\n      speak(memCards[a]);\n      if (matched.length === memCards.length) {\n        document.getElementById('memory-status').textContent = '\ud83c\udfc6 You matched them all!';\n        setTimeout(() => showCelebration({\n          emoji: '\ud83e\udde0',\n          title: 'Memory Master!',\n          sub: 'You matched all the pairs!',\n          score: `${matchScore} perfect matches! \ud83c\udfc6`\n        }), 400);\n      }\n    } else {\n      setTimeout(() => {\n        document.querySelectorAll('.mem-card')[a].classList.remove('revealed');\n        document.querySelectorAll('.mem-card')[b].classList.remove('revealed');\n        revealed = [];\n        lockBoard = false;\n      }, 900);\n    }\n  }\n}\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// STORIES\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nfunction initStories() {\n  const container = document.getElementById('story-cards');\n  container.innerHTML = '';\n  STORIES.forEach(story => {\n    const card = document.createElement('div');\n    card.className = 'story-card';\n    card.innerHTML = `\n      <div class=\"story-thumb\">${story.emoji}</div>\n      <div class=\"story-info\">\n        <div class=\"story-name\">${story.name}</div>\n        <div class=\"story-meta\">Ages ${story.age} \u00b7 ${story.pages.length} pages</div>\n      </div>\n      <div class=\"story-arrow\">\u203a</div>\n    `;\n    card.onclick = () => openStory(story.id);\n    container.appendChild(card);\n  });\n}\n\nfunction openStory(id) {\n  currentStory = STORIES[id];\n  currentPage = 0;\n  document.getElementById('reader-title').textContent = currentStory.name;\n  renderPage();\n  showScreen('reader');\n  stats.stories++;\n  addActivity({ icon: '\ud83d\udcd6', name: currentStory.name, time: 'Just now', score: '\u2b50\u2b50\u2b50' });\n}\n\nfunction renderPage() {\n  const page = currentStory.pages[currentPage];\n  document.getElementById('scene-emoji').textContent = page.emoji;\n\n  // Word-by-word with clickable spans\n  const words = page.text.split(' ');\n  const textEl = document.getElementById('story-text');\n  textEl.innerHTML = words.map((w, i) =>\n    `<span class=\"word\" onclick=\"speakWord('${w.replace(/[^a-zA-Z]/g,'')}', this)\">${w}</span>`\n  ).join(' ');\n\n  // Page dots\n  const dots = document.getElementById('page-dots');\n  dots.innerHTML = currentStory.pages.map((_, i) =>\n    `<div class=\"page-dot ${i === currentPage ? 'active' : ''}\" onclick=\"goToPage(${i})\"></div>`\n  ).join('');\n\n  // Nav buttons\n  document.getElementById('prev-page-btn').style.opacity = currentPage === 0 ? '0.4' : '1';\n  document.getElementById('next-page-btn').textContent = currentPage === currentStory.pages.length - 1 ? '\ud83c\udf89 Done!' : 'Next \u25b6';\n}\n\nfunction goToPage(i) {\n  stopReading();\n  currentPage = i;\n  renderPage();\n}\n\nfunction nextPage() {\n  stopReading();\n  if (currentPage < currentStory.pages.length - 1) {\n    currentPage++;\n    renderPage();\n  } else {\n    showCelebration({\n      emoji: '\ud83d\udcd6',\n      title: 'Story Complete!',\n      sub: currentStory.name,\n      score: '\u2b50\u2b50\u2b50 Great reading!'\n    });\n    setTimeout(() => showScreen('stories-list'), 100);\n  }\n}\n\nfunction prevPage() {\n  stopReading();\n  if (currentPage > 0) {\n    currentPage--;\n    renderPage();\n  }\n}\n\nfunction readAloud() {\n  const page = currentStory.pages[currentPage];\n  const words = document.querySelectorAll('.story-text .word');\n  stopReading();\n\n  const utterance = new SpeechSynthesisUtterance(page.text);\n  if (teacherVoice) utterance.voice = teacherVoice;\n  utterance.rate = 0.72;\n  utterance.pitch = 0.95;\n  utterance.volume = 0.75;\n\n  let wordIndex = 0;\n  utterance.onboundary = (e) => {\n    words.forEach(w => w.classList.remove('highlight'));\n    if (wordIndex < words.length) {\n      words[wordIndex].classList.add('highlight');\n      wordIndex++;\n    }\n  };\n  utterance.onend = () => {\n    words.forEach(w => w.classList.remove('highlight'));\n  };\n\n  window.speechSynthesis.speak(utterance);\n}\n\nfunction stopReading() { if(window.ReactNativeWebView){window.ReactNativeWebView.postMessage(JSON.stringify({type:\"STOP\"}));}\n  window.speechSynthesis.cancel();\n  document.querySelectorAll('.story-text .word').forEach(w => w.classList.remove('highlight'));\n}\n\nfunction speakWord(word, el) {\n  document.querySelectorAll('.story-text .word').forEach(w => w.classList.remove('highlight'));\n  el.classList.add('highlight');\n  speak(word);\n  setTimeout(() => el.classList.remove('highlight'), 1500);\n}\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// SPEECH \u2014 Warm Teacher Voice\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nlet teacherVoice = null;\n\nfunction loadTeacherVoice() {\n  if (!('speechSynthesis' in window)) return;\n  const load = () => {\n    const voices = window.speechSynthesis.getVoices();\n    // Priority order: prefer female US English voices\n    const preferred = [\n      'Samantha', 'Karen', 'Moira', 'Fiona', // macOS/iOS female\n      'Microsoft Zira', 'Microsoft Jenny',     // Windows female\n      'Google US English',                      // Chrome female\n    ];\n    for (const name of preferred) {\n      const v = voices.find(v => v.name.includes(name));\n      if (v) { teacherVoice = v; break; }\n    }\n    // Fallback: any female en-US voice\n    if (!teacherVoice) {\n      teacherVoice = voices.find(v =>\n        v.lang.startsWith('en') && v.name.toLowerCase().includes('female')\n      ) || voices.find(v => v.lang.startsWith('en')) || null;\n    }\n  };\n  if (window.speechSynthesis.getVoices().length) load();\n  window.speechSynthesis.onvoiceschanged = load;\n}\n\nfunction buildPhrase(card) {\n  if (currentDeck === 'Letters') return `${card.front} is for ${card.word}. ${card.word}.`;\n  if (currentDeck === 'Numbers') return `The number ${card.front}. ${card.word}.`;\n  if (currentDeck === 'Animals') return `This is a ${card.word}!`;\n  if (currentDeck === 'Colors') return `The color ${card.word}.`;\n  if (currentDeck === 'Shapes') return `This shape is a ${card.word}. ${card.word}.`;\n  return card.word;\n}\n\nfunction speakTeacher(text) { if(window.ReactNativeWebView){window.ReactNativeWebView.postMessage(JSON.stringify({type:\"SPEAK\",text:text}));return;}\n  if (!('speechSynthesis' in window)) return;\n  window.speechSynthesis.cancel();\n  const u = new SpeechSynthesisUtterance(text);\n  if (teacherVoice) u.voice = teacherVoice;\n  u.rate = 0.72;    // gentle and clear\n  u.pitch = 0.95;   // soft, calm \u2014 not high or loud\n  u.volume = 0.75;  // quieter, not shouting\n  window.speechSynthesis.speak(u);\n}\n\nfunction speak(text) {\n  speakTeacher(text);\n}\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// DASHBOARD\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nfunction initDashboard() {\n  document.getElementById('stat-time').textContent = stats.time;\n  document.getElementById('stat-cards').textContent = stats.cards;\n  document.getElementById('stat-stories').textContent = stats.stories;\n  document.getElementById('stat-streak').textContent = stats.streak;\n\n  const list = document.getElementById('activity-list');\n  list.innerHTML = activities.map(a => `\n    <div class=\"activity-item\">\n      <div class=\"activity-icon\">${a.icon}</div>\n      <div class=\"activity-info\">\n        <div class=\"activity-name\">${a.name}</div>\n        <div class=\"activity-time\">${a.time}</div>\n      </div>\n      <div class=\"activity-score\">${a.score}</div>\n    </div>\n  `).join('');\n}\n\nfunction addActivity(activity) {\n  activities.unshift(activity);\n  if (activities.length > 10) activities.pop();\n}\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// SETTINGS\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nfunction toggleSetting(key) {\n  settings[key] = !settings[key];\n  const toggle = document.getElementById('toggle-' + key);\n  toggle.classList.toggle('on', settings[key]);\n  if (key === 'bedtime') {\n    document.body.classList.toggle('bedtime', settings.bedtime);\n  }\n}\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// PREMIUM\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nfunction showPremium() {\n  document.getElementById('premium-modal').classList.add('open');\n}\n\nfunction closePremium(e) {\n  if (!e || e.target === document.getElementById('premium-modal')) {\n    document.getElementById('premium-modal').classList.remove('open');\n  }\n}\n\nfunction unlockPremium() {\n  closePremium();\n  showToast('\ud83c\udf1f Welcome to Premium!');\n}\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// CELEBRATION\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nconst CONFETTI_COLORS = ['#FF7A2F','#FFD166','#06D6A0','#118AB2','#9B5DE5','#EF476F','#FFD166'];\n\nfunction showCelebration({ emoji, title, sub, score }) {\n  document.getElementById('celeb-emoji').textContent = emoji;\n  document.getElementById('celeb-title').textContent = title;\n  document.getElementById('celeb-sub').textContent = sub;\n  document.getElementById('celeb-score').textContent = score || '';\n\n  // Launch confetti\n  const wrap = document.getElementById('confetti-wrap');\n  wrap.innerHTML = '';\n  for (let i = 0; i < 40; i++) {\n    const piece = document.createElement('div');\n    piece.className = 'confetti-piece';\n    piece.style.cssText = `\n      left: ${Math.random() * 100}%;\n      background: ${CONFETTI_COLORS[Math.floor(Math.random() * CONFETTI_COLORS.length)]};\n      width: ${Math.random() * 8 + 6}px;\n      height: ${Math.random() * 8 + 6}px;\n      border-radius: ${Math.random() > 0.5 ? '50%' : '2px'};\n      animation-duration: ${Math.random() * 1.5 + 1}s;\n      animation-delay: ${Math.random() * 0.5}s;\n    `;\n    wrap.appendChild(piece);\n  }\n\n  document.getElementById('celebration').classList.add('open');\n  speakTeacher(`${title} Amazing job! You are so smart!`);\n  stats.streak = Math.min(stats.streak + 1, 7);\n  initStreak();\n}\n\nfunction closeCelebration() {\n  document.getElementById('celebration').classList.remove('open');\n  document.getElementById('confetti-wrap').innerHTML = '';\n}\n\nfunction showToast(msg) {\n  const toast = document.getElementById('toast');\n  toast.textContent = msg;\n  toast.classList.add('show');\n  setTimeout(() => toast.classList.remove('show'), 2500);\n}\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// STREAK\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nfunction initStreak() {\n  const dots = document.getElementById('streak-dots');\n  dots.innerHTML = Array(7).fill(0).map((_, i) =>\n    `<div class=\"streak-dot ${i < stats.streak ? 'done' : ''}\"></div>`\n  ).join('');\n  document.getElementById('streak-display').textContent = `${stats.streak} days`;\n}\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// SCREEN CHANGE HOOKS\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nconst originalShowScreen = showScreen;\nwindow.showScreen = function(id) {\n  originalShowScreen(id);\n  if (id === 'flashcards') initFlashcards();\n  if (id === 'stories-list') initStories();\n  if (id === 'dashboard') initDashboard();\n};\n\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n// INIT\n// \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n\nloadTeacherVoice();\ninitStreak();\n</script>\n<!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 CELEBRATION \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n<div class=\"celebration-overlay\" id=\"celebration\">\n  <div class=\"celebration-box\">\n    <div class=\"confetti-wrap\" id=\"confetti-wrap\"></div>\n    <div class=\"celeb-stars\">\u2b50\u2b50\u2b50</div>\n    <div class=\"celeb-emoji\" id=\"celeb-emoji\">\ud83c\udf89</div>\n    <div class=\"celeb-title\" id=\"celeb-title\">Amazing!</div>\n    <div class=\"celeb-sub\" id=\"celeb-sub\">You finished the deck!</div>\n    <div class=\"celeb-score\" id=\"celeb-score\"></div>\n    <button class=\"celeb-btn\" onclick=\"closeCelebration()\">Keep Learning! \ud83d\ude80</button>\n  </div>\n</div>\n\n</body>\n</html>\n";

export default function App() {
  const webViewRef = useRef(null);

  const handleMessage = (event) => {
    try {
      const data = JSON.parse(event.nativeEvent.data);
      if (data.type === 'SPEAK') {
        Speech.stop();
        Speech.speak(data.text, {
          language: 'en-US',
          pitch: 0.95,
          rate: 0.72,
        });
      } else if (data.type === 'STOP') {
        Speech.stop();
      }
    } catch (e) {}
  };

  return (
    <View style={styles.container}>
      <StatusBar hidden={true} />
      <WebView
        ref={webViewRef}
        source={{ html: HTML }}
        style={styles.webview}
        javaScriptEnabled={true}
        originWhitelist={['*']}
        mediaPlaybackRequiresUserAction={false}
        allowsInlineMediaPlayback={true}
        mixedContentMode="always"
        domStorageEnabled={true}
        onMessage={handleMessage}
      />
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: '#FFF8F0' },
  webview: { flex: 1 },
});